const fetch = require("node-fetch");

const API_KEY = String($ytApiKey || "").trim();
const selectedNo = parseInt(String($flow.input || "").trim(), 10);

if (!API_KEY) return "❌ Missing ytApiKey";
if (!selectedNo) return "❌ Enter a valid number.";

const videos = $flow.state?.ytVideos || [];
const picked = videos.find(v => v.no === selectedNo);

if (!picked) return "❌ Invalid number selection.";

async function getJson(url) {
  const res = await fetch(url);
  const data = await res.json();
  if (!res.ok || data?.error) {
    const msg = data?.error?.message || `HTTP ${res.status}`;
    throw new Error(msg);
  }
  return data;
}

function formatNumber(n) {
  const s = String(n ?? "");
  return s.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

try {

  const videoId = picked.videoId;

  const vUrl =
    `https://www.googleapis.com/youtube/v3/videos?part=snippet,statistics,contentDetails&id=${videoId}&key=${API_KEY}`;
  const vData = await getJson(vUrl);

  const v = vData.items[0];

  const payload = {
    title: v.snippet.title,
    videoUrl: `https://www.youtube.com/watch?v=${videoId}`,
    views: formatNumber(v.statistics.viewCount),
    likes: v.statistics.likeCount ? formatNumber(v.statistics.likeCount) : "Hidden",
    comments: formatNumber(v.statistics.commentCount),
    duration: v.contentDetails.duration,
    description: v.snippet.description
  };

  return JSON.stringify(payload, null, 2);

} catch (e) {
  return `❌ Error: ${e.message}`;
}

