inputs.customFunctionJavascriptFunction:
const fetch = require("node-fetch");

const API_KEY = String($ytApiKey || "").trim();
const channelQuery = String($flow?.input || "").trim();

if (!API_KEY) return "❌ Missing ytApiKey";
if (!channelQuery) return "❌ Please enter a channel name.";

async function getJson(url) {
  const res = await fetch(url);
  const data = await res.json();
  if (!res.ok || data?.error) {
    const msg = data?.error?.message || `HTTP ${res.status}`;
    throw new Error(msg);
  }
  return data;
}

function formatNumber(n) {
  const s = String(n ?? "");
  return s.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

try {

  // 1) Search channel
  const searchUrl =
    `https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&maxResults=1&q=${encodeURIComponent(channelQuery)}&key=${API_KEY}`;
  const searchData = await getJson(searchUrl);

  const first = searchData?.items?.[0];
  if (!first) return "❌ Channel not found.";

  const channelId = first.snippet.channelId;

  // 2) Get channel statistics
  const chUrl =
    `https://www.googleapis.com/youtube/v3/channels?part=snippet,statistics&id=${channelId}&key=${API_KEY}`;
  const chData = await getJson(chUrl);

  const ch = chData.items[0];

  const channelTitle = ch.snippet.title;
  const subscriberCount = ch.statistics.subscriberCount;
  const videoCount = ch.statistics.videoCount;
  const viewCount = ch.statistics.viewCount;

  // 3) Get latest videos
  const vidsUrl =
    `https://www.googleapis.com/youtube/v3/search?part=snippet&channelId=${channelId}&order=date&type=video&maxResults=10&key=${API_KEY}`;
  const vidsData = await getJson(vidsUrl);

  const videos = vidsData.items.map((v, idx) => ({
    no: idx + 1,
    videoId: v.id.videoId,
    title: v.snippet.title
  }));

  // Save in state
  $flow.state = $flow.state || {};
  $flow.state.ytVideos = videos;

  const table = videos
    .map(v => `${v.no}. ${v.title}`)
    .join("\n");

  return `
Channel: ${channelTitle}
Subscribers: ${formatNumber(subscriberCount)}
Total Videos: ${formatNumber(videoCount)}
Total Views: ${formatNumber(viewCount)}

Latest Videos:
${table}

Type the number of the video you want details for.
`;

} catch (e) {
  return `❌ Error: ${e.message}`;
}

